'use client';

import { useState, useMemo } from 'react';
import { useParams, useRouter } from 'next/navigation';
import { motion } from 'framer-motion';
import {
  ArrowLeft,
  Heart,
  MessageCircle,
  Share2,
  Clock,
  Check,
} from 'lucide-react';
import Sidebar from '@/components/layout/Sidebar';
import RightPanel from '@/components/layout/RightPanel';
import MobileNav from '@/components/layout/MobileNav';
import { mockArticles } from '@/data/articles';
import { mockComments } from '@/data/comments';
import { formatDate, formatNumber, generateId } from '@/lib/utils';
import { useAuth } from '@/contexts/AuthContext';
import { Comment } from '@/types';

export default function ArticleDetailPage() {
  const params = useParams();
  const router = useRouter();
  const { currentUser, isAuthenticated, isLiked, toggleLike, isShared, toggleShare } = useAuth();
  const articleId = params.id as string;

  const article = mockArticles.find((a) => a.id === articleId);
  const [comments, setComments] = useState<Comment[]>(
    mockComments.filter((c) => c.articleId === articleId)
  );
  const [newComment, setNewComment] = useState('');
  const [replyTo, setReplyTo] = useState<string | null>(null);
  const [replyText, setReplyText] = useState('');
  const [showShareConfirm, setShowShareConfirm] = useState(false);

  if (!article) {
    return (
      <div className="min-h-screen flex items-center justify-center" style={{ background: '#000' }}>
        <p style={{ color: '#71767B' }}>Không tìm thấy bài viết</p>
      </div>
    );
  }

  const liked = isLiked(article.id);
  const shared = isShared(article.id);

  const handleComment = () => {
    if (!newComment.trim() || !currentUser) return;
    const comment: Comment = {
      id: generateId(),
      content: newComment,
      author: currentUser,
      articleId: article.id,
      parentId: null,
      createdAt: new Date().toISOString(),
      likesCount: 0,
      replies: [],
    };
    setComments((prev) => [comment, ...prev]);
    setNewComment('');
  };

  const handleReply = (parentId: string) => {
    if (!replyText.trim() || !currentUser) return;
    const reply: Comment = {
      id: generateId(),
      content: replyText,
      author: currentUser,
      articleId: article.id,
      parentId,
      createdAt: new Date().toISOString(),
      likesCount: 0,
    };
    setComments((prev) =>
      prev.map((c) =>
        c.id === parentId
          ? { ...c, replies: [...(c.replies || []), reply] }
          : c
      )
    );
    setReplyTo(null);
    setReplyText('');
  };

  const handleShare = () => {
    toggleShare(article.id);
    setShowShareConfirm(true);
    setTimeout(() => setShowShareConfirm(false), 2000);
  };

  return (
    <div className="min-h-screen" style={{ background: '#000' }}>
      <Sidebar />
      <main className="lg:ml-[275px] xl:mr-[350px] min-h-screen border-r" style={{ borderColor: '#2F3336' }}>
        {/* Header */}
        <div className="sticky top-0 z-30 flex items-center gap-4 px-4 py-3 border-b"
          style={{ background: 'rgba(0,0,0,0.8)', backdropFilter: 'blur(12px)', borderColor: '#2F3336' }}
        >
          <button
            onClick={() => router.back()}
            className="p-2 rounded-full transition-colors hover:bg-white/10"
            style={{ color: '#E7E9EA' }}
          >
            <ArrowLeft className="w-5 h-5" />
          </button>
          <h1 className="text-lg font-bold" style={{ color: '#E7E9EA' }}>Bài viết</h1>
        </div>

        {/* Article */}
        <motion.article
          initial={{ opacity: 0, y: 10 }}
          animate={{ opacity: 1, y: 0 }}
          className="px-4 py-4 border-b"
          style={{ borderColor: '#2F3336' }}
        >
          {/* Author */}
          <div className="flex items-center gap-3 mb-4">
            <img
              src={article.author.avatar}
              alt={article.author.name}
              className="w-12 h-12 rounded-full"
              style={{ background: '#2F3336' }}
            />
            <div>
              <p className="font-bold" style={{ color: '#E7E9EA' }}>{article.author.name}</p>
              <p className="text-sm" style={{ color: '#71767B' }}>{article.author.bio}</p>
            </div>
          </div>

          {/* Title */}
          <h1 className="text-2xl font-bold mb-3 leading-tight" style={{ color: '#E7E9EA' }}>
            {article.title}
          </h1>

          {/* Cover */}
          {article.coverImage && (
            <div className="rounded-2xl overflow-hidden mb-4 border" style={{ borderColor: '#2F3336' }}>
              <img src={article.coverImage} alt={article.title} className="w-full max-h-[400px] object-cover" />
            </div>
          )}

          {/* Content */}
          <div className="prose" dangerouslySetInnerHTML={{ __html: article.content }} />

          {/* Meta */}
          <div className="flex items-center gap-2 mt-4 pt-4 border-t" style={{ borderColor: '#2F3336' }}>
            <Clock className="w-4 h-4" style={{ color: '#71767B' }} />
            <span className="text-sm" style={{ color: '#71767B' }}>
              {new Date(article.createdAt).toLocaleDateString('vi-VN', {
                day: 'numeric',
                month: 'long',
                year: 'numeric',
                hour: '2-digit',
                minute: '2-digit',
              })}
            </span>
            <span className="text-sm px-2 py-0.5 rounded-full ml-2"
              style={{ background: `${article.topic.color}20`, color: article.topic.color }}
            >
              {article.topic.icon} {article.topic.name}
            </span>
          </div>

          {/* Stats */}
          <div className="flex items-center gap-6 mt-3 pt-3 border-t" style={{ borderColor: '#2F3336' }}>
            <span className="text-sm" style={{ color: '#71767B' }}>
              <strong style={{ color: '#E7E9EA' }}>{formatNumber(article.commentsCount)}</strong> bình luận
            </span>
            <span className="text-sm" style={{ color: '#71767B' }}>
              <strong style={{ color: '#E7E9EA' }}>{formatNumber(article.likesCount + (liked ? 1 : 0))}</strong> lượt thích
            </span>
            <span className="text-sm" style={{ color: '#71767B' }}>
              <strong style={{ color: '#E7E9EA' }}>{formatNumber(article.sharesCount)}</strong> chia sẻ
            </span>
          </div>

          {/* Actions */}
          <div className="flex items-center justify-around mt-3 pt-3 border-t" style={{ borderColor: '#2F3336' }}>
            <button className="flex items-center gap-2 py-2 px-4 rounded-full transition-colors hover:bg-blue-500/10"
              style={{ color: '#71767B' }}
            >
              <MessageCircle className="w-5 h-5" />
              <span className="text-sm">Bình luận</span>
            </button>
            <motion.button
              whileTap={{ scale: 1.2 }}
              onClick={() => isAuthenticated && toggleLike(article.id)}
              className="flex items-center gap-2 py-2 px-4 rounded-full transition-colors"
              style={{
                color: liked ? '#F91880' : '#71767B',
                background: liked ? 'rgba(249,24,128,0.1)' : 'transparent',
              }}
            >
              <Heart className="w-5 h-5" fill={liked ? '#F91880' : 'none'} />
              <span className="text-sm">Thích</span>
            </motion.button>
            <button
              onClick={handleShare}
              className="flex items-center gap-2 py-2 px-4 rounded-full transition-colors relative"
              style={{
                color: shared ? '#00BA7C' : '#71767B',
                background: shared ? 'rgba(0,186,124,0.1)' : 'transparent',
              }}
            >
              {shared ? <Check className="w-5 h-5" /> : <Share2 className="w-5 h-5" />}
              <span className="text-sm">{shared ? 'Đã chia sẻ' : 'Chia sẻ'}</span>
            </button>
          </div>

          {/* Share confirmation toast */}
          {showShareConfirm && (
            <motion.div
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0 }}
              className="fixed bottom-20 left-1/2 -translate-x-1/2 px-4 py-2 rounded-full text-sm font-medium z-50"
              style={{ background: '#F97316', color: '#fff' }}
            >
              {shared ? '✅ Đã chia sẻ lên trang cá nhân' : '❌ Đã bỏ chia sẻ'}
            </motion.div>
          )}
        </motion.article>

        {/* Comment Input */}
        {isAuthenticated && currentUser && (
          <div className="px-4 py-3 border-b flex gap-3" style={{ borderColor: '#2F3336' }}>
            <img src={currentUser.avatar} alt="" className="w-10 h-10 rounded-full shrink-0" style={{ background: '#2F3336' }} />
            <div className="flex-1">
              <textarea
                value={newComment}
                onChange={(e) => setNewComment(e.target.value)}
                placeholder="Viết bình luận..."
                rows={2}
                className="w-full px-3 py-2 rounded-xl border text-sm resize-none focus:outline-none transition-colors"
                style={{ background: '#16181C', borderColor: '#2F3336', color: '#E7E9EA' }}
                onFocus={(e) => (e.target.style.borderColor = '#F97316')}
                onBlur={(e) => (e.target.style.borderColor = '#2F3336')}
              />
              <div className="flex justify-end mt-2">
                <motion.button
                  whileHover={{ scale: 1.02 }}
                  whileTap={{ scale: 0.98 }}
                  onClick={handleComment}
                  disabled={!newComment.trim()}
                  className="px-4 py-1.5 rounded-full text-sm font-semibold text-white disabled:opacity-40 transition-opacity"
                  style={{ background: '#F97316' }}
                >
                  Gửi
                </motion.button>
              </div>
            </div>
          </div>
        )}

        {/* Comments */}
        <div>
          {comments.map((comment) => (
            <motion.div
              key={comment.id}
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              className="px-4 py-3 border-b"
              style={{ borderColor: '#2F3336' }}
            >
              <div className="flex gap-3">
                <img src={comment.author.avatar} alt="" className="w-10 h-10 rounded-full shrink-0" style={{ background: '#2F3336' }} />
                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-2">
                    <span className="font-bold text-sm" style={{ color: '#E7E9EA' }}>{comment.author.name}</span>
                    <span className="text-xs" style={{ color: '#71767B' }}>· {formatDate(comment.createdAt)}</span>
                  </div>
                  <p className="text-sm mt-1 leading-relaxed" style={{ color: '#E7E9EA' }}>{comment.content}</p>
                  <div className="flex items-center gap-4 mt-2">
                    <button className="text-xs flex items-center gap-1 transition-colors" style={{ color: '#71767B' }}>
                      <Heart className="w-3.5 h-3.5" /> {comment.likesCount}
                    </button>
                    <button
                      onClick={() => setReplyTo(replyTo === comment.id ? null : comment.id)}
                      className="text-xs transition-colors"
                      style={{ color: '#71767B' }}
                    >
                      Trả lời
                    </button>
                  </div>

                  {/* Reply input */}
                  {replyTo === comment.id && currentUser && (
                    <div className="mt-3 flex gap-2">
                      <img src={currentUser.avatar} alt="" className="w-8 h-8 rounded-full shrink-0" style={{ background: '#2F3336' }} />
                      <div className="flex-1">
                        <textarea
                          value={replyText}
                          onChange={(e) => setReplyText(e.target.value)}
                          placeholder={`Trả lời ${comment.author.name}...`}
                          rows={2}
                          className="w-full px-3 py-2 rounded-xl border text-sm resize-none focus:outline-none"
                          style={{ background: '#16181C', borderColor: '#2F3336', color: '#E7E9EA' }}
                          autoFocus
                        />
                        <div className="flex justify-end gap-2 mt-1">
                          <button onClick={() => setReplyTo(null)} className="text-xs px-3 py-1 rounded-full" style={{ color: '#71767B' }}>
                            Hủy
                          </button>
                          <button
                            onClick={() => handleReply(comment.id)}
                            disabled={!replyText.trim()}
                            className="text-xs px-3 py-1 rounded-full text-white disabled:opacity-40"
                            style={{ background: '#F97316' }}
                          >
                            Trả lời
                          </button>
                        </div>
                      </div>
                    </div>
                  )}

                  {/* Replies */}
                  {comment.replies && comment.replies.length > 0 && (
                    <div className="mt-3 space-y-3 pl-4 border-l-2" style={{ borderColor: '#2F3336' }}>
                      {comment.replies.map((reply) => (
                        <div key={reply.id} className="flex gap-2">
                          <img src={reply.author.avatar} alt="" className="w-8 h-8 rounded-full shrink-0" style={{ background: '#2F3336' }} />
                          <div>
                            <div className="flex items-center gap-2">
                              <span className="font-bold text-xs" style={{ color: '#E7E9EA' }}>{reply.author.name}</span>
                              <span className="text-xs" style={{ color: '#71767B' }}>· {formatDate(reply.createdAt)}</span>
                            </div>
                            <p className="text-sm mt-0.5" style={{ color: '#E7E9EA' }}>{reply.content}</p>
                          </div>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              </div>
            </motion.div>
          ))}

          {comments.length === 0 && (
            <div className="py-12 text-center" style={{ color: '#71767B' }}>
              <MessageCircle className="w-10 h-10 mx-auto mb-3 opacity-50" />
              <p className="text-sm">Chưa có bình luận nào</p>
              <p className="text-xs mt-1">Hãy là người đầu tiên bình luận!</p>
            </div>
          )}
        </div>
      </main>
      <RightPanel />
      <MobileNav />
    </div>
  );
}
